package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	osexec "os/exec"
	"path/filepath"
	"regexp"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
)

// NowFunc allows tests to override time.Now for deterministic PreserveRef output.
var NowFunc = time.Now

// PreserveRef builds the documented hidden ref for a preserved iteration.
func PreserveRef(beadID, baseRev string) string {
	shortSHA := baseRev
	if len(shortSHA) > 12 {
		shortSHA = shortSHA[:12]
	}
	timestamp := NowFunc().UTC().Format("20060102T150405Z")
	return fmt.Sprintf("refs/ddx/iterations/%s/%s-%s", beadID, timestamp, shortSHA)
}

// GateCheckResult records the outcome of one required execution gate.
type GateCheckResult struct {
	DefinitionID string `json:"definition_id"`
	Required     bool   `json:"required"`
	ExitCode     int    `json:"exit_code"`
	// Status is "pass", "fail", or "skipped".
	Status string `json:"status"`
	Stdout string `json:"stdout,omitempty"`
	Stderr string `json:"stderr,omitempty"`
	// Ratchet captures the ratchet evaluation when the gate declared
	// thresholds. Populated for both pass and fail decisions so HELIX can
	// distinguish ratchet outcomes from generic command failures.
	Ratchet *RatchetEvidence `json:"ratchet,omitempty"`
}

// RatchetEvidence is the machine-readable record of one ratchet evaluation
// performed before landing. Threshold/Observed carry the authored ratchet
// and the observed value; Decision is "pass" or "fail"; Reason provides a
// short explanation of what was compared ("observed 310 ms > ratchet 250 ms").
type RatchetEvidence struct {
	DefinitionID string  `json:"definition_id"`
	MetricID     string  `json:"metric_id,omitempty"`
	Comparison   string  `json:"comparison,omitempty"`
	Threshold    float64 `json:"threshold"`
	Observed     float64 `json:"observed"`
	Unit         string  `json:"unit,omitempty"`
	Decision     string  `json:"decision"`
	Reason       string  `json:"reason,omitempty"`
}

// RatchetPreserveReason marks a landing that was preserved because a declared
// ratchet was not met. Callers match on this exact string (via the landing
// result's Reason field) to bucket ratchet-preserved attempts apart from
// generic gate failures.
const RatchetPreserveReason = "ratchet miss"

// executeBeadChecks is the machine-readable schema for checks.json.
// Written by the orchestrator when gate evaluation runs.
type executeBeadChecks struct {
	AttemptID       string            `json:"attempt_id"`
	EvaluatedAt     time.Time         `json:"evaluated_at"`
	Summary         string            `json:"summary"`
	Results         []GateCheckResult `json:"results"`
	RatchetSummary  string            `json:"ratchet_summary,omitempty"`
	RatchetEvidence []RatchetEvidence `json:"ratchet_evidence,omitempty"`
}

// OrchestratorGitOps abstracts the git operations needed by the parent-side
// orchestrator for preserving worker results under iteration refs.
//
// NOTE: The Merge(dir, rev) method that existed here before the land
// coordinator redesign has been DELETED. All target-branch writes now flow
// through Land() in execute_bead_land.go and its per-project serialized
// coordinator. See ddx-8746d8a6 / ddx-e14efc58 / ddx-6aa50e57 for the
// rationale: the old path produced "chore: checkpoint before merge" noise
// and workers racing on the same projectRoot could corrupt each other's
// intermediate state. Land() serializes through a single goroutine and
// uses `git merge --no-ff` when the target has advanced, so the worker's
// commit is never rewritten and replay sees the same inputs it originally saw.
//
// The LandingAdvancer field on BeadLandingOptions is the coordinator
// injection point for LandBeadResult callers that need to ff the target
// branch. When LandingAdvancer is nil (the interactive single-bead CLI),
// LandBeadResult falls back to preserving the result under
// refs/ddx/iterations/<bead-id>/... rather than modifying the target branch.
type OrchestratorGitOps interface {
	UpdateRef(dir, ref, sha string) error
}

// BeadLandingOptions controls how the orchestrator lands a completed worker result.
type BeadLandingOptions struct {
	// NoMerge skips the land step and preserves the result under
	// refs/ddx/iterations/<bead-id>/... instead.
	NoMerge bool

	// WtPath is the path to a worktree checked out at ResultRev, used for gate
	// evaluation. When empty, gate evaluation is skipped (the worktree has
	// typically been cleaned up by the time the orchestrator runs).
	WtPath string

	// GovernIDs are the governing artifact IDs to use for gate evaluation.
	// Only used when WtPath is non-empty. Typically extracted from the worker's
	// manifest artifact via ExtractGoverningIDsFromManifest.
	GovernIDs []string

	// ChecksArtifactPath is the absolute path to write checks.json. Optional.
	ChecksArtifactPath string
	// ChecksArtifactRel is the relative path stored in the result for checks.json.
	ChecksArtifactRel string

	// LandingAdvancer, when non-nil, replaces the old in-process Merge step
	// with the coordinator-pattern Land() call. The callback is expected to
	// run the local land sequence serialized against other submissions for
	// the same projectRoot. When nil, LandBeadResult falls back to
	// preserving the result under refs/ddx/iterations/<bead-id>/...
	// rather than touching the target branch.
	LandingAdvancer func(res *ExecuteBeadResult) (*LandResult, error)
}

// BeadLandingResult records the outcome of the orchestrator's landing step.
type BeadLandingResult struct {
	// Outcome is one of: "merged", "preserved", "no-changes".
	Outcome string `json:"outcome"`
	// Reason is a human-readable explanation of the outcome.
	Reason string `json:"reason,omitempty"`
	// PreserveRef is set when the result was preserved under refs/ddx/iterations/...
	PreserveRef string `json:"preserve_ref,omitempty"`
	// GateResults holds the outcome of each required execution gate.
	GateResults []GateCheckResult `json:"gate_results,omitempty"`
	// RequiredExecSummary is "pass", "fail", or "skipped".
	RequiredExecSummary string `json:"required_exec_summary,omitempty"`
	// ChecksFile is the relative path to checks.json when gate results were written.
	ChecksFile string `json:"checks_file,omitempty"`
	// RatchetEvidence aggregates every ratchet-evaluated gate's evidence for
	// the attempt. Surfaced separately from GateResults so HELIX and other
	// consumers can tell apart ratchet outcomes from generic gate failures.
	RatchetEvidence []RatchetEvidence `json:"ratchet_evidence,omitempty"`
	// RatchetSummary is "pass", "fail", or "" (no ratchets evaluated).
	RatchetSummary string `json:"ratchet_summary,omitempty"`
}

// LandBeadResult is the parent-side orchestrator. It receives a completed worker
// result and decides whether to merge, preserve, or report no-changes. All
// Merge, UpdateRef, gate evaluation, and preserve-ref management live here.
// The worker (ExecuteBead) must not call any of these operations.
//
// Outcome rules:
//   - ResultRev == BaseRev → "no-changes" (agent made no commits)
//   - ExitCode != 0 with commits → "preserved" (agent failed but left output)
//   - Gate failed → "preserved"
//   - NoMerge → "preserved"
//   - Default → attempt merge; on conflict → "preserved"
func LandBeadResult(projectRoot string, res *ExecuteBeadResult, gitOps OrchestratorGitOps, opts BeadLandingOptions) (*BeadLandingResult, error) {
	landing := &BeadLandingResult{}

	// Agent failed with no commits: report as error (not no-changes).
	// Prefer res.Reason (e.g. HeadRev failure set by worker) over res.Error
	// (agent error) so the primary context failure is surfaced as the reason.
	agentFailed := res.ExitCode != 0 || res.Outcome == ExecuteBeadOutcomeTaskFailed
	if agentFailed && res.ResultRev == res.BaseRev {
		landing.Outcome = "error"
		switch {
		case res.Reason != "":
			landing.Reason = res.Reason
		case res.Error != "":
			landing.Reason = res.Error
		default:
			landing.Reason = "agent execution failed"
		}
		return landing, nil
	}

	// No changes from the worker: nothing to land.
	if res.ResultRev == res.BaseRev {
		if res.Outcome == ExecuteBeadOutcomeTaskNoEvidence || res.FailureMode == FailureModeNoEvidenceProduced {
			landing.Outcome = "no-evidence"
			if res.Reason != "" {
				landing.Reason = res.Reason
			} else if res.Error != "" {
				landing.Reason = res.Error
			} else {
				landing.Reason = "agent exited without a commit or no_changes_rationale.txt"
			}
			return landing, nil
		}
		landing.Outcome = "no-changes"
		if res.NoChangesRationale != "" {
			landing.Reason = res.NoChangesRationale
		} else {
			landing.Reason = "agent made no commits"
		}
		return landing, nil
	}

	// Integrity violation detected by the worker's structured post-agent
	// validation (ddx-725b65b4): the agent exited cleanly and left commits, but
	// the attempt rewrote its commit, left empty pre-commit gate evidence, or
	// left tracked files uncommitted. Preserve the commits for operator review
	// under an iteration ref with the integrity reason rather than letting them
	// merge as success; the specific explanation rides on res.Error.
	if res.FailureMode == FailureModeAttemptIntegrity && res.ResultRev != res.BaseRev {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		landing.Reason = AttemptIntegrityPreserveReason
		return landing, nil
	}

	// Agent failed but produced commits: preserve without attempting merge.
	if agentFailed {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		landing.Reason = "agent execution failed"
		return landing, nil
	}

	// Evaluate requi...[truncated]

// Package failclass implements the FEAT-004 failure-classification routing
// policy applied by ddx work between bead-execution attempts (bead
// ddx-d27a1895).
//
// It provides four things the queue drain composes:
//
//   - Classify maps a single attempt Outcome to exactly one routing Action,
//     applying the normative failure-classification table.
//   - Escalate owns the single one-hop middle->max tier escalation, which only
//     a typed genuine failure triggers.
//   - Pool enforces a per-pool in-flight max-attempt cap that prevents a
//     multi-worker stampede when many workers fail concurrently.
//   - Pool also carries the global (per-pool, not per-bead) cooldown applied on
//     quota exhaustion.
//
// The classification table is normative; it is inlined here from the bead body
// because the upstream FEAT-004 routing addendum lives in the fizeau repo and
// is not reachable from a cold ddx agent.
package failclass

import (
	"sync"
	"time"
)

// Outcome is the typed result of a single ddx-work attempt. Every Outcome maps
// to exactly one Action via Classify.
type Outcome string

const (
	// OutcomeSuccess: the attempt satisfied the bead's acceptance criteria.
	OutcomeSuccess Outcome = "success"
	// OutcomeAlreadySatisfied: the bead was already satisfied before work.
	OutcomeAlreadySatisfied Outcome = "already_satisfied"
	// OutcomeNoChanges: the agent produced nothing and wrote a rationale.
	OutcomeNoChanges Outcome = "no_changes"
	// OutcomeGenuineFailure: tests fail after real work; acceptance unmet.
	// This is the only outcome that can trigger a tier escalation.
	OutcomeGenuineFailure Outcome = "genuine_failure"
	// OutcomeDirtyWorktree: dirty worktree or partial write.
	OutcomeDirtyWorktree Outcome = "dirty_worktree"
	// OutcomeTransport: provider transport failure (i/o timeout, conn refused,
	// 5xx).
	OutcomeTransport Outcome = "transport"
	// OutcomeQuota: quota exhausted (retry_after).
	OutcomeQuota Outcome = "quota"
	// OutcomeAuth: auth/config missing.
	OutcomeAuth Outcome = "auth"
	// OutcomeSetup: toolchain/setup failure.
	OutcomeSetup Outcome = "setup"
	// OutcomeTimeout: timeout / no-progress watchdog.
	OutcomeTimeout Outcome = "timeout"
	// OutcomeMergeConflict: merge/land conflict.
	OutcomeMergeConflict Outcome = "merge_conflict"
)

// Action is the single routing action selected for an Outcome.
type Action string

const (
	// ActionCloseBead: close the bead (success path).
	ActionCloseBead Action = "close_bead"
	// ActionCloseOrUnclaim: close or unclaim per the agent's rationale; never
	// escalate the tier.
	ActionCloseOrUnclaim Action = "close_or_unclaim"
	// ActionEscalateTier: escalate the tier exactly once (middle->max).
	ActionEscalateTier Action = "escalate_tier"
	// ActionResetRetrySameTier: clean/reset the worktree and retry at the same
	// tier (not an escalation).
	ActionResetRetrySameTier Action = "reset_retry_same_tier"
	// ActionRerouteSameTier: reroute to another dispatchable candidate at the
	// same tier; no tier change.
	ActionRerouteSameTier Action = "reroute_same_tier"
	// ActionGlobalCooldown: put the whole pool to sleep until quota reset; not
	// a per-bead mutation, not an escalation.
	ActionGlobalCooldown Action = "global_cooldown"
	// ActionOperatorAttention: explicit bead state transition to the operator
	// lane (not a notification or an indefinite wait).
	ActionOperatorAttention Action = "operator_attention"
	// ActionUnclaimRetryLater: unclaim and retry later; not an escalation.
	ActionUnclaimRetryLater Action = "unclaim_retry_later"
)

// Escalates reports whether the Action mutates the tier. Only
// ActionEscalateTier escalates; this is the single guard the escalation owner
// (ddx work) checks before calling Escalate.
func (a Action) Escalates() bool {
	return a == ActionEscalateTier
}

// ClassifyContext carries the routing state needed to resolve the tier- and
// attempt-conditional rows of the table (genuine failure and timeout).
type ClassifyContext struct {
	// AtMaxTier reports whether the attempt already ran at the maximum tier. A
	// genuine failure at the max tier goes to the operator lane instead of
	// escalating.
	AtMaxTier bool
	// SameTierRetried reports whether a same-tier retry was already consumed. A
	// second timeout (after one same-tier retry) goes to the operator lane.
	SameTierRetried bool
}

// Classify maps a single attempt Outcome to exactly one Action, applying the
// normative failure-classification table.
//
// Only OutcomeGenuineFailure can produce ActionEscalateTier, and only when the
// attempt was not already at the max tier. The no_changes, dirty, transport,
// quota, auth, setup, timeout, and merge-conflict outcomes never escalate.
func Classify(outcome Outcome, ctx ClassifyContext) Action {
	switch outcome {
	case OutcomeSuccess, OutcomeAlreadySatisfied:
		return ActionCloseBead
	case OutcomeNoChanges:
		return ActionCloseOrUnclaim
	case OutcomeGenuineFailure:
		// Single one-hop middle->max escalation; a max-tier genuine failure
		// stops escalating and goes to the operator lane.
		if ctx.AtMaxTier {
			return ActionOperatorAttention
		}
		return ActionEscalateTier
	case OutcomeDirtyWorktree:
		return ActionResetRetrySameTier
	case OutcomeTransport:
		return ActionRerouteSameTier
	case OutcomeQuota:
		return ActionGlobalCooldown
	case OutcomeAuth, OutcomeSetup:
		return ActionOperatorAttention
	case OutcomeTimeout:
		// Clean + same-tier retry once, then operator-attention.
		if ctx.SameTierRetried {
			return ActionOperatorAttention
		}
		return ActionResetRetrySameTier
	case OutcomeMergeConflict:
		return ActionUnclaimRetryLater
	default:
		// Unknown outcomes go to the operator lane rather than silently
		// escalating or retrying.
		return ActionOperatorAttention
	}
}

// Tier is a routing capability tier. Escalation is a single one-hop edge from
// TierMiddle to TierMax; no other edge escalates.
type Tier int

const (
	// TierLow is the cheapest tier and is never an escalation target.
	TierLow Tier = iota
	// TierMiddle is the default starting tier for dispatch.
	TierMiddle
	// TierMax is the strongest tier and the only escalation target.
	TierMax
)

// Escalate performs the single one-hop middle->max escalation and reports
// whether it changed the tier. Escalation is idempotent: only TierMiddle
// escalates (to TierMax); every other tier — including a tier already at
// TierMax — is returned unchanged with escalated=false. This enforces "exactly
// one middle->max" per dispatch chain.
func Escalate(t Tier) (next Tier, escalated bool) {
	if t == TierMiddle {
		return TierMax, true
	}
	return t, false
}

// Pool tracks per-pool in-flight attempts and the global cooldown for a single
// dispatch pool. It is safe for concurrent use by multiple workers.
//
// The in-flight cap prevents a multi-worker stampede: when many workers fail
// concurrently against the same pool, at most maxInFlight attempts may hold a
// slot at once. The cooldown is global to the pool (applied on quota
// exhaustion), not a per-bead mutation.
type Pool struct {
	mu            sync.Mutex
	name          string
	maxInFlight   int
	inFlight      int
	cooldownUntil time.Time
	now           func() time.Time
}

// NewPool returns a Pool with the given name and in-flight cap. A non-positive
// maxInFlight is clamped to 1. The clock defaults to time.Now and can be
// overridden for tests via SetClock.
func NewPool(name string, maxInFlight int) *Pool {
	if maxInFlight < 1 {
		maxInFlight = 1
	}
	return &Pool{
		name:        name,
		maxInFlight: maxInFlight,
		now:         time.Now,
	}
}

// SetClock overrides the pool's time source. It exists so tests can advance
// time without sleeping; the bead requires bounded, non-hanging tests.
func (p *Pool) SetClock(now func() time.Time) {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.now = now
}

// Name returns the pool's name.
func (p *Pool) Name() string {
	return p.name
}

// Acquire attempts to take one in-flight slot. It returns false when the pool
// is in cooldown or the in-flight cap is already reached; otherwise it takes a
// slot and returns true. Every successful Acquire must be paired with a
// Release.
func (p *Pool) Acquire() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.now().Before(p.cooldownUntil) {
		return false
	}
	if p.inFlight >= p.maxInFlight {
		return false
	}
	p.inFlight++
	return true
}

// Release returns one in-flight slot. It never drops below zero.
func (p *Pool) Release() {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.inFlight > 0 {
		p.inFlight--
	}
}

// InFlight returns the current number of held in-flight slots.
func (p *Pool) InFlight() int {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.inFlight
}

// EnterCooldown applies a global pool cooldown of duration d (typically the
// quota retry_after). It is global to the pool, not a per-bead mutation:
// subsequent Acquire calls fail until the cooldown elapses. A later, longer
// cooldown extends the window; a shorter one never shortens an active window.
func (p *Pool) EnterCooldown(d time.Duration) {
	p.mu.Lock()
	defer p.mu.Unlock()
	until := p.now().Add(d)
	if until.After(p.cooldownUntil) {
		p.cooldownUntil = until
	}
}

// InCooldown reports whether the pool is currently in a global cooldown.
func (p *Pool) InCooldown() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.now().Before(p.cooldownUntil)
}

